class Solution:
    def maxTotalReward(self, rewardValues):
        vals = sorted(set(rewardValues))
        # brute-force DP with set of reachable totals
        reachable = {0}
        for v in vals:
            new_reach = set()
            for x in reachable:
                if x < v:
                    new_reach.add(x + v)
            reachable |= new_reach
        return max(reachable)

