class Solution:
    def maxTotalReward(self, rewardValues):
        vals = sorted(set(rewardValues))
        # dp[x] = True if total x is reachable
        max_val = vals[-1]
        dp = [False] * (2 * max_val)
        dp[0] = True
        for v in vals:
            # iterate backwards to avoid using v twice in one pass
            for x in range(v - 1, -1, -1):
                if dp[x]:
                    dp[x + v] = True
        for i in range(2 * max_val - 1, -1, -1):
            if dp[i]:
                return i
        return 0

